-- Update REPAIR_QUOTE email template — multi-line + tax breakdown.
--
-- The hero card now shows the tax-INCLUSIVE grand total as the headline
-- number (that's what the customer pays). A new Quote Breakdown card
-- between Item Details and Notes itemises the lines + subtotal + tax +
-- grand total, plus the QB rounding notice.
--
-- New tokens (all populated by api_sendTemplateEmail_ from the Repair
-- row's persisted columns):
--   {{QUOTE_LINE_ITEMS_HTML}}  pre-rendered <tr> rows for the lines table
--   {{QUOTE_SUBTOTAL}}         pre-tax sum, formatted "1,234.56"
--   {{QUOTE_TAX_AREA_NAME}}    e.g., "Kent"
--   {{QUOTE_TAX_RATE}}         e.g., "10.4%"
--   {{QUOTE_TAX_AMOUNT}}       formatted "12.34"
--   {{QUOTE_GRAND_TOTAL}}      formatted "1,246.90"
--
-- Back-compat: legacy single-amount quotes (no line items) are sent
-- with a one-row line table (REPAIR / 1 / amount), tax=$0, and grand
-- total = subtotal = amount. Renders cleanly in the same shell.
--
-- {{QUOTE_AMOUNT}} kept for back-compat — equals subtotal under the
-- new model.

UPDATE public.email_templates
SET
  subject = 'Repair Quote Ready: {{CLIENT_NAME}} Item ID {{ITEM_ID}}',
  body = $body$<div style="background:#F5F2EE;padding:32px 16px 48px;font-family:'Inter',Arial,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="max-width:660px;margin:0 auto"><tr><td><table width="100%" cellpadding="0" cellspacing="0" border="0" style="padding:0 8px 24px"><tr><td valign="middle"><table cellpadding="0" cellspacing="0" border="0"><tr><td valign="middle" style="padding-right:10px"><img src="https://static.wixstatic.com/media/a38fbc_e4bdb945b21f4b9f8b10873799e8f8f1~mv2.png" alt="Stride" width="40" height="40" style="display:block" /></td><td valign="middle"><div style="font-family:'Oswald',Arial,sans-serif;font-size:24px;font-weight:600;letter-spacing:2px;color:#1C1C1C;text-transform:uppercase;line-height:1;margin-bottom:3px">STRIDE</div><div style="font-family:'Oswald',Arial,sans-serif;font-size:10px;font-weight:400;letter-spacing:5px;color:#888888;text-transform:uppercase;line-height:1">LOGISTICS</div></td></tr></table></td><td align="right" valign="middle"><span style="font-size:11px;color:#999999;letter-spacing:1px">Repair Quote</span></td></tr></table><div style="background:#1C1C1C;border-radius:20px;padding:48px 40px;margin-bottom:16px;color:#fff"><div style="font-size:10px;font-weight:500;letter-spacing:4px;color:#E8692A;text-transform:uppercase;margin-bottom:16px">Repair {{REPAIR_ID}}</div><div style="font-size:32px;font-weight:300;color:#fff;line-height:1.2;margin-bottom:12px">Total: <span style="color:#E8692A;font-weight:500">${{QUOTE_GRAND_TOTAL}}</span></div><div style="font-size:14px;font-weight:300;line-height:1.8;color:rgba(255,255,255,0.7)">Repair quote ready for {{CLIENT_NAME}} — item {{ITEM_ID}}. Approve or decline inside Stride Hub.</div><table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-top:32px;border-top:1px solid rgba(255,255,255,0.1);padding-top:24px"><tr><td style="padding-right:16px;vertical-align:top"><div style="font-size:10px;font-weight:500;letter-spacing:2px;color:rgba(255,255,255,0.45);text-transform:uppercase;margin-bottom:6px">Item ID</div><div style="font-size:16px;font-weight:500;color:#fff;word-break:break-word">{{ITEM_ID}}</div></td><td style="padding-right:16px;vertical-align:top"><div style="font-size:10px;font-weight:500;letter-spacing:2px;color:rgba(255,255,255,0.45);text-transform:uppercase;margin-bottom:6px">Total (incl. tax)</div><div style="font-size:16px;font-weight:500;color:#fff;word-break:break-word">${{QUOTE_GRAND_TOTAL}}</div></td><td style="padding-right:16px;vertical-align:top"><div style="font-size:10px;font-weight:500;letter-spacing:2px;color:rgba(255,255,255,0.45);text-transform:uppercase;margin-bottom:6px">Repair ID</div><div style="font-size:16px;font-weight:500;color:#fff;word-break:break-word">{{REPAIR_ID}}</div></td></tr></table></div><div style="background:#FFFFFF;border-radius:20px;padding:40px;margin-bottom:16px"><div style="font-size:10px;font-weight:500;letter-spacing:4px;color:#E8692A;text-transform:uppercase;margin-bottom:12px">Item Details</div><div style="font-size:14px;font-weight:300;line-height:1.8;color:#666666">{{ITEM_TABLE_HTML}}</div></div><div style="background:#FFFFFF;border-radius:20px;padding:40px;margin-bottom:16px"><div style="font-size:10px;font-weight:500;letter-spacing:4px;color:#E8692A;text-transform:uppercase;margin-bottom:12px">Quote Breakdown</div><table width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;font-size:13px;color:#1C1C1C"><thead><tr style="border-bottom:1px solid #E5E5E5"><th align="left" style="padding:8px 0;font-size:10px;font-weight:600;letter-spacing:1.5px;color:#888;text-transform:uppercase">Service</th><th align="right" style="padding:8px 0;font-size:10px;font-weight:600;letter-spacing:1.5px;color:#888;text-transform:uppercase">Qty</th><th align="right" style="padding:8px 0;font-size:10px;font-weight:600;letter-spacing:1.5px;color:#888;text-transform:uppercase">Rate</th><th align="right" style="padding:8px 0;font-size:10px;font-weight:600;letter-spacing:1.5px;color:#888;text-transform:uppercase">Amount</th></tr></thead><tbody>{{QUOTE_LINE_ITEMS_HTML}}</tbody><tfoot><tr><td colspan="3" align="right" style="padding:14px 12px 6px 0;font-size:13px;color:#666">Subtotal</td><td align="right" style="padding:14px 0 6px;font-size:13px;color:#1C1C1C">${{QUOTE_SUBTOTAL}}</td></tr><tr><td colspan="3" align="right" style="padding:0 12px 6px 0;font-size:13px;color:#666">Sales tax ({{QUOTE_TAX_AREA_NAME}} · {{QUOTE_TAX_RATE}})</td><td align="right" style="padding:0 0 6px;font-size:13px;color:#1C1C1C">${{QUOTE_TAX_AMOUNT}}</td></tr><tr style="border-top:2px solid #1C1C1C"><td colspan="3" align="right" style="padding:14px 12px 0 0;font-size:14px;font-weight:600;color:#1C1C1C">Total due</td><td align="right" style="padding:14px 0 0;font-size:18px;font-weight:600;color:#E8692A">${{QUOTE_GRAND_TOTAL}}</td></tr></tfoot></table><div style="margin-top:16px;padding:12px 14px;background:#F5F2EE;border-radius:10px;font-size:11px;color:#888;line-height:1.6">Sales tax shown is computed at the {{QUOTE_TAX_AREA_NAME}} rate. The QuickBooks invoice you receive will compute tax independently and may differ by a few cents due to rounding.</div></div><div style="background:#EDE9E3;border-radius:20px;padding:40px;margin-bottom:16px"><div style="font-size:10px;font-weight:500;letter-spacing:4px;color:#E8692A;text-transform:uppercase;margin-bottom:12px">Notes</div><div style="font-size:14px;font-weight:300;line-height:1.8;color:#666666"><p style="margin:0 0 8px"><strong style="font-weight:500;color:#1C1C1C">Inspector notes:</strong> {{TASK_NOTES}}</p><p style="margin:0"><strong style="font-weight:500;color:#1C1C1C">Additional notes:</strong> {{NOTES}}</p></div></div><table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin:8px 0 16px"><tr><td align="center" style="padding:0 8px"><a href="{{APP_DEEP_LINK}}" style="display:inline-block;background:#E8692A;color:#fff;font-weight:600;font-size:11px;letter-spacing:2px;text-transform:uppercase;text-decoration:none;padding:16px 32px;border-radius:100px;margin:4px">Approve or Decline</a></td></tr></table><div style="background:#EDE9E3;border-radius:20px;padding:40px;margin-bottom:16px"><div style="font-size:10px;font-weight:500;letter-spacing:4px;color:#E8692A;text-transform:uppercase;margin-bottom:12px">Stride Hub</div><div style="font-size:22px;font-weight:300;color:#1C1C1C;line-height:1.3;margin-bottom:16px">Your inventory portal</div><div style="font-size:14px;font-weight:300;line-height:1.8;color:#666666"><p style="margin:0 0 12px">Track everything anytime at <a href="{{APP_URL}}/inventory" style="color:#E8692A;font-weight:500;text-decoration:none">www.mystridehub.com</a> — shipments, tasks, repairs, and will calls are all there.</p><div style="font-weight:500;color:#1C1C1C;margin:16px 0 6px">New to Stride Hub?</div><ul style="margin:0 0 12px;padding-left:18px"><li>Your login is this email address</li><li>Click <strong style="font-weight:500;color:#1C1C1C">Forgot Password</strong> to set your password</li><li>Watch for the reset link in your inbox</li></ul><div style="font-weight:500;color:#1C1C1C;margin:16px 0 6px">Once you're in, you can:</div><ul style="margin:0 0 12px;padding-left:18px"><li>Request inspections, repairs, and will calls</li><li>Edit sidemarks, vendors, and item details</li><li>See all your services and billing in one place</li></ul><div style="font-weight:500;color:#E8692A;margin:16px 0 6px">Quick heads-up on sidemarks</div><p style="margin:0">If you'd like your invoice split by sidemark, make sure everything's updated before your next invoice runs — we're not able to separate charges by sidemark after invoices go out.</p></div></div><div style="font-size:11px;font-weight:300;color:#BBBBBB;line-height:2.4;padding:24px 8px 0;text-align:center">Stride Logistics · Kent, WA · whse@stridenw.com</div></td></tr></table></div>$body$,
  updated_at = now()
WHERE template_key = 'REPAIR_QUOTE';
